import React from 'react';

const NAV = [
  { section: 'Overview', items: [
    { id: 'dashboard',  icon: 'layout-dashboard', label: 'Dashboard' },
    { id: 'new-claim',  icon: 'plus',             label: 'New claim' },
  ]},
  { section: 'My Claims', items: [
    { id: 'my-claims',  icon: 'file-invoice', label: 'My claims', badge: 'my' },
  ]},
  { section: 'Supervisor', items: [
    { id: 'supervisor', icon: 'clipboard-check', label: 'Approve queue', badge: 'sup' },
  ]},
  { section: 'HRS Payroll', items: [
    { id: 'hrs',  icon: 'database',      label: 'Persal capture', badge: 'hrs' },
    { id: 'ecm',  icon: 'cloud-upload',  label: 'ECM mandates',   badge: 'ecm' },
  ]},
  { section: 'DMC Payroll', items: [
    { id: 'dmc',  icon: 'cash',          label: 'Payment run' },
  ]},
  { section: 'Admin', items: [
    { id: 'tariffs', icon: 'table',     label: 'Tariff table' },
    { id: 'reports', icon: 'chart-bar', label: 'Reports' },
  ]},
];

export default function Sidebar({ active, onNav, badges }) {
  return (
    <aside style={{
      width: 'var(--sidebar-w)', background: 'var(--surface)',
      borderRight: '0.5px solid var(--border)',
      position: 'fixed', top: 0, left: 0, height: '100vh',
      display: 'flex', flexDirection: 'column',
      overflowY: 'auto', zIndex: 10,
    }}>
      <div style={{ padding: '1.25rem', borderBottom: '0.5px solid var(--border)', marginBottom: 8 }}>
        <div style={{ fontSize: 13, fontWeight: 500 }}>GPG Travel Claims</div>
        <div style={{ fontSize: 11, color: 'var(--text2)', marginTop: 2 }}>Persal-integrated system</div>
      </div>

      <div style={{ flex: 1, padding: '0 8px' }}>
        {NAV.map(group => (
          <div key={group.section} style={{ marginBottom: 4 }}>
            <div style={{
              fontSize: 10, fontWeight: 500, color: 'var(--text3)',
              textTransform: 'uppercase', letterSpacing: '.08em',
              padding: '8px 8px 3px',
            }}>{group.section}</div>
            {group.items.map(item => {
              const isActive = active === item.id;
              const cnt = item.badge ? (badges[item.badge] || 0) : 0;
              return (
                <div key={item.id}
                  onClick={() => onNav(item.id)}
                  style={{
                    display: 'flex', alignItems: 'center', gap: 8,
                    padding: '6px 8px', borderRadius: 'var(--radius)',
                    cursor: 'pointer', fontSize: 13,
                    background: isActive ? 'var(--blue-bg)' : 'transparent',
                    color: isActive ? 'var(--blue-text)' : 'var(--text2)',
                    fontWeight: isActive ? 500 : 400,
                    marginBottom: 1,
                    transition: 'background .12s',
                  }}
                >
                  <i className={`ti ti-${item.icon}`} style={{ fontSize: 16 }} />
                  <span style={{ flex: 1 }}>{item.label}</span>
                  {cnt > 0 && (
                    <span style={{
                      fontSize: 10, padding: '2px 6px',
                      borderRadius: 10, fontWeight: 500,
                      background: isActive ? 'var(--blue-text)' : 'var(--amber-bg)',
                      color: isActive ? 'var(--blue-bg)' : 'var(--amber-text)',
                    }}>{cnt}</span>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <div style={{
        padding: '1rem 1.25rem',
        borderTop: '0.5px solid var(--border)',
        marginTop: 'auto',
      }}>
        <div style={{ fontSize: 11, color: 'var(--text3)' }}>Signed in as</div>
        <div style={{ fontSize: 13, fontWeight: 500, marginTop: 2 }}>T. Dlamini</div>
        <div style={{ fontSize: 11, color: 'var(--text2)' }}>Official · HRS Payroll</div>
      </div>
    </aside>
  );
}
